 44→    const handleSubmit = () => {
 45→        const trimmed = body.trim();
 46→        if (!trimmed || trimmed.length > MAX_CHARS) return;
 47→
 48→        const userData = user?.userData?.[0];
 49→
 50→        const data = {
 51→            comment: trimmed,
 52→            paragraph_index: paragraphIndex,
 53→            paragraph_fingerprint: fingerprint,
 54→        };
 55→        if (replyTo) {
 56→            data.parent_id = replyTo.id;
 57→        }
 58→
 59→        const optimisticComment = {
 60→            id: `optimistic-${Date.now()}`,
 61→            comment: trimmed,
 62→            paragraph_index: paragraphIndex,
 63→            parent_id: replyTo?.id || null,
 64→            created_at: new Date().toISOString(),
 65→            user_id: userData?.id,
 66→            users: {
